import spacy

# Load the small English model once for efficiency
try:
    nlp = spacy.load("en_core_web_sm")
except OSError:
    print("Downloading spaCy model. Run 'python -m spacy download en_core_web_sm' if this fails.")
    spacy.cli.download("en_core_web_sm")
    nlp = spacy.load("en_core_web_sm")

def get_dependencies(sentence: str) -> dict:
    """
    Parses a sentence and returns a dictionary mapping tokens to their
    head and children.
    """
    doc = nlp(sentence)
    dependencies = {}
    for token in doc:
        dependencies[token.text] = {
            'head': token.head.text,
            'children': [child.text for child in token.children]
        }
    return dependencies
